object LoggingConfig {
    var enableFileLogging = true
    var enableConsoleLogging = true
    var enableDetailedLogging = true
    var maxLogFileSize = 10 * 1024 * 1024 // 10MB
    var maxLogFiles = 5
}

fun setupLogging(context: Context) {
    if (LoggingConfig.enableConsoleLogging) {
        Timber.plant(VerboseDebugTree())
    }
    
    if (LoggingConfig.enableFileLogging) {
        Timber.plant(FileLoggingTree(context))
    }
    
    Timber.plant(CrashlyticsTree())
}

class VerboseDebugTree : Timber.DebugTree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val threadName = Thread.currentThread().name
        val timeStamp = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault()).format(Date())
        val priorityLabel = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "U"
        }
        
        val fullMessage = StringBuilder()
        fullMessage.append("[$timeStamp][$priorityLabel][$threadName][$tag] $message")
        
        if (t != null) {
            fullMessage.append("\n")
            fullMessage.append(getStackTraceString(t))
        }
        
        super.log(priority, tag, fullMessage.toString(), null)
    }
    
    override fun createStackElementTag(element: StackTraceElement): String {
        return String.format(
            "%s.%s(%s:%d)",
            element.className.substringAfterLast('.'),
            element.methodName,
            element.fileName,
            element.lineNumber
        )
    }
}

class FileLoggingTree(private val context: Context) : Timber.Tree() {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault())
    private val logDir = File(context.getExternalFilesDir(null), "logs")
    private val coroutineScope = CoroutineScope(Dispatchers.IO)
    
    init {
        if (!logDir.exists()) {
            logDir.mkdirs()
        }
        cleanOldLogs()
    }
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority >= Log.INFO) {
            coroutineScope.launch {
                writeToFile(priority, tag, message, t)
            }
        }
    }
    
    private fun writeToFile(priority: Int, tag: String?, message: String, t: Throwable?) {
        try {
            val currentFile = getCurrentLogFile()
            val priorityLabel = when (priority) {
                Log.VERBOSE -> "VERBOSE"
                Log.DEBUG -> "DEBUG"
                Log.INFO -> "INFO"
                Log.WARN -> "WARN"
                Log.ERROR -> "ERROR"
                Log.ASSERT -> "ASSERT"
                else -> "UNKNOWN"
            }
            
            val logEntry = StringBuilder()
            logEntry.append("[${dateFormat.format(Date())}] ")
            logEntry.append("[$priorityLabel] ")
            logEntry.append("[${Thread.currentThread().name}] ")
            logEntry.append("[${tag ?: "NO_TAG"}] ")
            logEntry.append(message)
            logEntry.append("\n")
            
            if (t != null) {
                logEntry.append(getStackTraceString(t))
                logEntry.append("\n")
            }
            
            currentFile.appendText(logEntry.toString())
            
            if (currentFile.length() > LoggingConfig.maxLogFileSize) {
                rotateLogFiles()
            }
        } catch (e: Exception) {
            Log.e("FileLoggingTree", "Error writing to log file", e)
        }
    }
    
    private fun getCurrentLogFile(): File {
        val fileName = "app_log_${SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(Date())}.txt"
        return File(logDir, fileName)
    }
    
    private fun rotateLogFiles() {
        val logFiles = logDir.listFiles()?.sortedByDescending { it.lastModified() } ?: return
        
        if (logFiles.size >= LoggingConfig.maxLogFiles) {
            logFiles.drop(LoggingConfig.maxLogFiles - 1).forEach { it.delete() }
        }
    }
    
    private fun cleanOldLogs() {
        val logFiles = logDir.listFiles()?.sortedByDescending { it.lastModified() } ?: return
        if (logFiles.size > LoggingConfig.maxLogFiles) {
            logFiles.drop(LoggingConfig.maxLogFiles).forEach { it.delete() }
        }
    }
}

