object AuthenticationLogger {
    private const val TAG = "Authentication"
    
    fun logLoginAttempt(username: String, method: String) {
        val details = mapOf(
            "username" to username,
            "method" to method,
            "timestamp" to System.currentTimeMillis(),
            "deviceInfo" to getDeviceInfo()
        )
        Timber.tag(TAG).i("Login attempt: ${formatDetails(details)}")
    }
    
    fun logLoginSuccess(username: String, userId: String, method: String, sessionId: String) {
        val details = mapOf(
            "username" to username,
            "userId" to userId,
            "method" to method,
            "sessionId" to sessionId,
            "timestamp" to System.currentTimeMillis(),
            "deviceInfo" to getDeviceInfo()
        )
        Timber.tag(TAG).i("Login successful: ${formatDetails(details)}")
    }
    
    fun logLoginFailure(username: String, method: String, reason: String, errorCode: String? = null) {
        val details = mutableMapOf(
            "username" to username,
            "method" to method,
            "reason" to reason,
            "timestamp" to System.currentTimeMillis(),
            "deviceInfo" to getDeviceInfo()
        )
        errorCode?.let { details["errorCode"] = it }
        
        Timber.tag(TAG).w("Login failed: ${formatDetails(details)}")
    }
    
    fun logLogout(username: String, userId: String, reason: String) {
        val details = mapOf(
            "username" to username,
            "userId" to userId,
            "reason" to reason,
            "timestamp" to System.currentTimeMillis()
        )
        Timber.tag(TAG).i("Logout: ${formatDetails(details)}")
    }
    
    fun logTokenRefresh(userId: String, success: Boolean, error: String? = null) {
        val details = mutableMapOf(
            "userId" to userId,
            "success" to success,
            "timestamp" to System.currentTimeMillis()
        )
        error?.let { details["error"] = it }
        
        Timber.tag(TAG).i("Token refresh: ${formatDetails(details)}")
    }
    
    fun logPasswordChange(userId: String, success: Boolean) {
        val details = mapOf(
            "userId" to userId,
            "success" to success,
            "timestamp" to System.currentTimeMillis()
        )
        Timber.tag(TAG).i("Password change: ${formatDetails(details)}")
    }
    
    private fun getDeviceInfo(): String {
        return "${android.os.Build.MANUFACTURER} ${android.os.Build.MODEL} (Android ${android.os.Build.VERSION.RELEASE})"
    }
    
    private fun formatDetails(details: Map<String, Any>): String {
        return details.entries.joinToString(", ") { "${it.key}=${it.value}" }
    }
}

object DatabaseLogger {
    private const val TAG = "Database"
    
    fun logQuery(query: String, params: List<Any?>? = null, duration: Long? = null) {
        val details = StringBuilder()
        details.append("Query: $query")
        
        if (!params.isNullOrEmpty()) {
            details.append("\nParameters: ${formatParams(params)}")
        }
        
        duration?.let {
            details.append("\nDuration: ${it}ms")
        }
        
        details.append("\nThread: ${Thread.currentThread().name}")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).v(details.toString())
    }
    
    fun logInsert(table: String, values: Map<String, Any?>, rowId: Long? = null) {
        val details = StringBuilder()
        details.append("INSERT into $table")
        details.append("\nValues: ${formatMap(values)}")
        rowId?.let { details.append("\nInserted Row ID: $it") }
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).d(details.toString())
    }
    
    fun logUpdate(table: String, values: Map<String, Any?>, whereClause: String?, whereArgs: List<Any?>?, rowsAffected: Int) {
        val details = StringBuilder()
        details.append("UPDATE $table")
        details.append("\nValues: ${formatMap(values)}")
        whereClause?.let { details.append("\nWhere: $it") }
        whereArgs?.let { details.append("\nWhere Args: ${formatParams(it)}") }
        details.append("\nRows Affected: $rowsAffected")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).d(details.toString())
    }
    
    fun logDelete(table: String, whereClause: String?, whereArgs: List<Any?>?, rowsAffected: Int) {
        val details = StringBuilder()
        details.append("DELETE from $table")
        whereClause?.let { details.append("\nWhere: $it") }
        whereArgs?.let { details.append("\nWhere Args: ${formatParams(it)}") }
        details.append("\nRows Affected: $rowsAffected")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).d(details.toString())
    }
    
    fun logTransaction(type: String, success: Boolean, operations: Int) {
        val details = StringBuilder()
        details.append("Transaction: $type")
        details.append("\nSuccess: $success")
        details.append("\nOperations: $operations")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).i(details.toString())
    }
    
    fun logError(operation: String, query: String?, error: Throwable) {
        val details = StringBuilder()
        details.append("Database Error: $operation")
        query?.let { details.append("\nQuery: $it") }
        
        Timber.tag(TAG).e(error, details.toString())
    }
    
    private fun formatParams(params: List<Any?>): String {
        return params.joinToString(", ") { 
            when (it) {
                null -> "NULL"
                is String -> "'$it'"
                else -> it.toString()
            }
        }
    }
    
    private fun formatMap(values: Map<String, Any?>): String {
        return values.entries.joinToString(", ") { 
            "${it.key}=${when (val v = it.value) {
                null -> "NULL"
                is String -> "'$v'"
                else -> v.toString()
            }}"
        }
    }
}

object ApiLogger {
    private const val TAG = "API"
    private val sensitiveHeaders = setOf("authorization", "api-key", "token", "cookie", "session")
    
    fun logRequest(
        method: String,
        url: String,
        headers: Map<String, String>,
        body: String?,
        requestId: String = UUID.randomUUID().toString()
    ) {
        val details = StringBuilder()
        details.append("=== API REQUEST ===")
        details.append("\nRequest ID: $requestId")
        details.append("\nMethod: $method")
        details.append("\nURL: $url")
        details.append("\nHeaders:")
        headers.forEach { (key, value) ->
            val displayValue = if (sensitiveHeaders.contains(key.lowercase())) {
                maskSensitiveData(value)
            } else {
                value
            }
            details.append("\n  $key: $displayValue")
        }
        
        if (body != null) {
            details.append("\nBody:")
            details.append("\n${formatBody(body)}")
        }
        
        details.append("\nThread: ${Thread.currentThread().name}")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).d(details.toString())
    }
    
    fun logResponse(
        requestId: String,
        statusCode: Int,
        headers: Map<String, String>,
        body: String?,
        duration: Long
    ) {
        val details = StringBuilder()
        details.append("=== API RESPONSE ===")
        details.append("\nRequest ID: $requestId")
        details.append("\nStatus Code: $statusCode")
        details.append("\nDuration: ${duration}ms")
        details.append("\nHeaders:")
        headers.forEach { (key, value) ->
            details.append("\n  $key: $value")
        }
        
        if (body != null) {
            details.append("\nBody:")
            details.append("\n${formatBody(body)}")
        }
        
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        val priority = if (statusCode >= 400) Log.WARN else Log.DEBUG
        when (priority) {
            Log.WARN -> Timber.tag(TAG).w(details.toString())
            else -> Timber.tag(TAG).d(details.toString())
        }
    }
    
    fun logError(
        requestId: String,
        method: String,
        url: String,
        error: Throwable,
        duration: Long? = null
    ) {
        val details = StringBuilder()
        details.append("=== API ERROR ===")
        details.append("\nRequest ID: $requestId")
        details.append("\nMethod: $method")
        details.append("\nURL: $url")
        duration?.let { details.append("\nDuration: ${it}ms") }
        
        Timber.tag(TAG).e(error, details.toString())
    }
    
    fun logRetry(requestId: String, attempt: Int, maxAttempts: Int, delay: Long) {
        val details = StringBuilder()
        details.append("API Retry")
        details.append("\nRequest ID: $requestId")
        details.append("\nAttempt: $attempt/$maxAttempts")
        details.append("\nDelay: ${delay}ms")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).i(details.toString())
    }
    
    private fun formatBody(body: String): String {
        return try {
            if (body.trim().startsWith("{") || body.trim().startsWith("[")) {
                JSONObject(body).toString(2)
            } else {
                body
            }
        } catch (e: Exception) {
            body
        }
    }
    
    private fun maskSensitiveData(value: String): String {
        return if (value.length > 8) {
            "${value.take(4)}...${value.takeLast(4)}"
        } else {
            "***"
        }
    }
}

object ExceptionLogger {
    private const val TAG = "Exception"
    
    fun logException(exception: Throwable, context: String? = null, additionalData: Map<String, Any>? = null) {
        val details = StringBuilder()
        details.append("=== EXCEPTION CAUGHT ===")
        context?.let { details.append("\nContext: $it") }
        details.append("\nException Type: ${exception.javaClass.simpleName}")
        details.append("\nMessage: ${exception.message}")
        
        additionalData?.let {
            details.append("\nAdditional Data:")
            it.forEach { (key, value) ->
                details.append("\n  $key: $value")
            }
        }
        
        details.append("\nThread: ${Thread.currentThread().name}")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        details.append("\n\nStack Trace:")
        details.append("\n${getStackTraceString(exception)}")
        
        exception.cause?.let { cause ->
            details.append("\n\nCaused by:")
            details.append("\n${getStackTraceString(cause)}")
        }
        
        Timber.tag(TAG).e(details.toString())
    }
    
    fun logHandledException(exception: Throwable, handled: Boolean, action: String? = null) {
        val details = StringBuilder()
        details.append("Exception Handled")
        details.append("\nException: ${exception.javaClass.simpleName}")
        details.append("\nMessage: ${exception.message}")
        details.append("\nHandled: $handled")
        action?.let { details.append("\nAction Taken: $it") }
        
        Timber.tag(TAG).w(exception, details.toString())
    }
    
    fun logUncaughtException(thread: Thread, exception: Throwable) {
        val details = StringBuilder()
        details.append("=== UNCAUGHT EXCEPTION ===")
        details.append("\nThread: ${thread.name}")
        details.append("\nException: ${exception.javaClass.simpleName}")
        details.append("\nMessage: ${exception.message}")
        details.append("\nTimestamp: ${System.currentTimeMillis()}")
        
        Timber.tag(TAG).e(exception, details.toString())
    }
}

fun getStackTraceString(t: Throwable): String {
    val sw = StringWriter()
    val pw = PrintWriter(sw)
    t.printStackTrace(pw)
    return sw.toString()
}

class GlobalExceptionHandler(
    private val defaultHandler: Thread.UncaughtExceptionHandler?
) : Thread.UncaughtExceptionHandler {
    
    override fun uncaughtException(thread: Thread, exception: Throwable) {
        ExceptionLogger.logUncaughtException(thread, exception)
        defaultHandler?.uncaughtException(thread, exception)
    }
    
    companion object {
        fun install() {
            val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
            Thread.setDefaultUncaughtExceptionHandler(GlobalExceptionHandler(defaultHandler))
        }
    }
}

object PerformanceLogger {
    private const val TAG = "Performance"
    
    fun logMethodExecution(methodName: String, duration: Long, params: Map<String, Any>? = null) {
        val details = StringBuilder()
        details.append("Method: $methodName")
        details.append("\nDuration: ${duration}ms")
        params?.let {
            details.append("\nParameters: ${it.entries.joinToString(", ") { "${it.key}=${it.value}" }}")
        }
        
        Timber.tag(TAG).v(details.toString())
    }
    
    fun logMemoryUsage(context: String) {
        val runtime = Runtime.getRuntime()
        val usedMemory = (runtime.totalMemory() - runtime.freeMemory()) / (1024 * 1024)
        val maxMemory = runtime.maxMemory() / (1024 * 1024)
        
        val details = StringBuilder()
        details.append("Memory Usage: $context")
        details.append("\nUsed: ${usedMemory}MB")
        details.append("\nMax: ${maxMemory}MB")
        details.append("\nPercentage: ${(usedMemory * 100 / maxMemory)}%")
        
        Timber.tag(TAG).d(details.toString())
    }
}

inline fun <T> measureExecutionTime(tag: String = "Execution", block: () -> T): T {
    val startTime = System.currentTimeMillis()
    val result = block()
    val duration = System.currentTimeMillis() - startTime
    PerformanceLogger.logMethodExecution(tag, duration)
    return result
}